package sync

import (
	"encoding/json"
	"fmt"
	"log"
	"strings"
	"time"

	"github.com/comuline/api/internal/models"
	"gorm.io/datatypes"
	"gorm.io/gorm"
	"gorm.io/gorm/clause"
)

const (
	mrtLine      = "MRT NORTH-SOUTH LINE"
	mrtRouteUp   = "LEBAKBULUS-BUNDARANHI"
	mrtRouteDown = "BUNDARANHI-LEBAKBULUS"
)

// MRTScheduleDirection represents a direction of travel.
type MRTScheduleDirection struct {
	Location string   `json:"location"` // "hi" (northbound to Bundaran HI) or "lb" (southbound to Lebak Bulus)
	Times    MRTTimes `json:"times"`
}

// MRTTimes holds weekday and weekend departure times.
type MRTTimes struct {
	Weekdays []string `json:"weekdays"`
	Weekends []string `json:"weekends"`
}

// MRTScheduleInput represents schedule data for one station with departure times.
type MRTScheduleInput struct {
	StationID  string
	Directions []MRTScheduleDirection
}

// BuildMRTSchedules converts MRT schedule inputs into Schedule model objects.
// It determines the correct departure times based on whether today is a weekday or weekend.
func BuildMRTSchedules(inputs []MRTScheduleInput, today time.Time, loc *time.Location) []models.Schedule {
	isWeekend := today.Weekday() == time.Saturday || today.Weekday() == time.Sunday

	var schedules []models.Schedule

	for _, input := range inputs {
		for _, dir := range input.Directions {
			var times []string
			if isWeekend {
				times = dir.Times.Weekends
			} else {
				times = dir.Times.Weekdays
			}

			route := mrtRouteUp
			destID := "BHI"
			originID := "LBB"
			if dir.Location == "lb" {
				route = mrtRouteDown
				destID = "LBB"
				originID = "BHI"
			}

			for i, t := range times {
				departsAt := parseScheduleTime(t, today, loc)

				// Generate a unique train ID based on direction and sequence.
				trainID := fmt.Sprintf("MRT-%s-%03d", strings.ToUpper(dir.Location), i+1)

				// Build schedule ID: station-trainID for uniqueness.
				scheduleID := fmt.Sprintf("%s-%s", input.StationID, trainID)

				meta, _ := json.Marshal(map[string]any{
					"is_active": true,
					"origin": map[string]string{
						"color": "#DD0067",
					},
				})

				schedules = append(schedules, models.Schedule{
					ID:            scheduleID,
					TrainID:       trainID,
					Line:          mrtLine,
					Route:         route,
					OriginID:      originID,
					DestinationID: destID,
					StationID:     input.StationID,
					DepartsAt:     departsAt,
					ArrivesAt:     departsAt, // MRT only provides departure time per station
					Metadata:      datatypes.JSON(meta),
				})
			}
		}
	}

	return schedules
}

// SyncMRTSchedules generates and upserts MRT schedule data into the database.
// It uses the hardcoded schedule data since the MRT API provides departure times.
func SyncMRTSchedules(db *gorm.DB) error {
	log.Println("syncing MRT schedules...")

	loc, _ := time.LoadLocation("Asia/Jakarta")
	today := time.Now().In(loc)

	inputs := buildMRTScheduleInputs()
	schedules := BuildMRTSchedules(inputs, today, loc)

	if len(schedules) == 0 {
		log.Println("no MRT schedules to sync")
		return nil
	}

	// Upsert in batches to avoid overwhelming the database.
	batchSize := 100
	for i := 0; i < len(schedules); i += batchSize {
		end := i + batchSize
		if end > len(schedules) {
			end = len(schedules)
		}

		batch := schedules[i:end]
		result := db.Clauses(clause.OnConflict{
			Columns: []clause.Column{{Name: "id"}},
			DoUpdates: clause.AssignmentColumns([]string{
				"train_id", "line", "route", "origin_id", "destination_id",
				"station_id", "departs_at", "arrives_at", "metadata", "updated_at",
			}),
		}).Create(&batch)

		if result.Error != nil {
			return fmt.Errorf("upserting MRT schedules batch: %w", result.Error)
		}
	}

	log.Printf("MRT schedule sync complete: %d schedules processed", len(schedules))
	return nil
}

